#include &lt;iostream&gt;#include &lt;cstdio&gt;#include &lt;cstdlib&gt;#include &lt;chrono&gt;using namespace std;using namespace std::chrono;// 利用宏定义自动识别系统平台，配置对应的运行命令#ifdef _WIN32const string GEN_CMD   = &quot;data.exe &gt; in.txt&quot;;const string TEST_CMD  = &quot;test.exe &lt; in.txt &gt; test_out.txt&quot;;const string BAOLI_CMD = &quot;baoli.exe &lt; in.txt &gt; baoli_out.txt&quot;;const string DIFF_CMD  = &quot;fc test_out.txt baoli_out.txt &gt; nul&quot;;#elseconst string GEN_CMD   = &quot;./data &gt; in.txt&quot;;const string TEST_CMD  = &quot;./test &lt; in.txt &gt; test_out.txt&quot;;const string BAOLI_CMD = &quot;./baoli &lt; in.txt &gt; baoli_out.txt&quot;;const string DIFF_CMD  = &quot;diff -w test_out.txt baoli_out.txt &gt; /dev/null&quot;;#endifint main() &#123;	int ok = 0, n = 100; // n 为测试数据的组数		cout &lt;&lt; &quot;开始对拍...&quot; &lt;&lt; endl;		for(int i = 1; i &lt;= n; i++)&#123;		// 1. 生成随机数据		system(GEN_CMD.c_str());				// 2. 运行待测试代码		system(TEST_CMD.c_str()); 				// 3. 运行暴力/正确代码，并使用 chrono 精确计时		auto begin = steady_clock::now();		system(BAOLI_CMD.c_str()); 		auto end = steady_clock::now();				// 获取真实流逝的毫秒数		auto t = duration_cast&lt;milliseconds&gt;(end - begin).count();				// 4. 比对输出结果		if(system(DIFF_CMD.c_str()))&#123;			printf(&quot;测试点#%d Wrong Answer
&quot;, i);			break; // 遇到 WA 直接退出，保留 in.txt 现场方便 Debug		&#125; else if(t &gt; 1000)&#123; // 假设时间限制为 1000ms			printf(&quot;暴力/测试代码 Time Limit Exceeded (用时 %lld ms)
&quot;, t);			break; // 建议超时也保留现场		&#125; else &#123;			printf(&quot;测试点#%d Accepted 用时 %lld ms
&quot;, i, t);			ok++; 		&#125;	&#125;		printf(&quot;
测试结束。
&quot;);	double res = 100.0 * ok / n;	printf(&quot;共 %d 组测试数据，AC数据 %d 组。 得分 %.1lf。
&quot;, n, ok, res);		return 0;&#125;
